namespace ComposeNet.SourceGenerators;

/// <summary>
/// Source text added to the user's compilation via
/// <see cref="Microsoft.CodeAnalysis.IncrementalGeneratorInitializationContext.RegisterPostInitializationOutput"/>.
/// </summary>
internal static class Attributes
{
    public const string Source = """
        // <auto-generated/>
        #nullable enable
        namespace ComposeNet
        {
            /// <summary>
            /// Apply at assembly scope to generate a named-bit
            /// <c>[Flags] internal enum &lt;EnumName&gt;</c> from the
            /// parameter shape of <typeparamref name="T"/>'s static
            /// method <paramref name="methodName"/>. Bit numbers match
            /// the Kotlin parameter index in the bytecode — the position
            /// the <c>$default</c> bitmask expects.
            /// </summary>
            [global::System.AttributeUsage(global::System.AttributeTargets.Assembly,
                                           AllowMultiple = true)]
            internal sealed class ComposeDefaultsAttribute<T> : global::System.Attribute
            {
                public ComposeDefaultsAttribute(string methodName, string enumName) { }
            }

            /// <summary>
            /// Apply at assembly scope to generate a named-bit
            /// <c>[Flags] internal enum &lt;EnumName&gt;</c> from an
            /// explicit positional parameter list. Use this overload
            /// when the Kotlin <c>$default</c>-bearing overload was
            /// stripped from the binding (mangled JVM name, inline-class
            /// param, etc.) and there is no <c>IMethodSymbol</c> to read.
            /// Each name occupies one bit at its index; prefix a name
            /// with <c>!</c> to consume the bit without emitting an
            /// enum member (e.g. params the caller always provides).
            /// </summary>
            [global::System.AttributeUsage(global::System.AttributeTargets.Assembly,
                                           AllowMultiple = true)]
            internal sealed class ComposeDefaultsAttribute : global::System.Attribute
            {
                public ComposeDefaultsAttribute(string enumName, params string[] parameterNames) { }
            }

            /// <summary>
            /// Apply to a <c>partial</c> static method on
            /// <c>ComposeBridges</c> to have ComposeNet.SourceGenerators
            /// emit its JNI-bridge body. The partial method declares the
            /// user-facing C# signature; the generator fills in cache
            /// fields, lazy class/method ID resolution, the JValue array,
            /// the <c>$default</c> bitmask, and the
            /// <c>try</c>/<c>finally</c> + <c>GC.KeepAlive</c> block.
            /// </summary>
            /// <remarks>
            /// <para><b>Class</b>: JNI-internal class name, e.g.
            /// <c>androidx/compose/material3/ButtonKt</c>.</para>
            /// <para><b>JvmName</b>: the (often mangled) Kotlin-emitted
            /// method name, e.g. <c>Button</c> or <c>Surface-T9BRK9s</c>.</para>
            /// <para><b>Signature</b>: full JNI signature string for the
            /// underlying static method. Ends in
            /// <c>...Composer;I*I)&lt;ReturnType&gt;</c> (one trailing
            /// <c>I</c> per <c>$changed</c> group plus one for
            /// <c>$default</c>) when the function has at least one
            /// defaultable parameter, or <c>...Composer;I*)&lt;ReturnType&gt;</c>
            /// when every parameter is required (no <c>$default</c> slot
            /// in the bytecode). The return-type token is <c>V</c> for
            /// <c>void</c> bridges or an <c>L...;</c> for state holders /
            /// factories.</para>
            /// <para><b>Defaults</b>: <c>typeof(XxxDefault)</c> — the
            /// <c>$default</c> bitmask enum produced by
            /// <see cref="ComposeDefaultsAttribute"/>. The generator reads
            /// the matching declarative <c>[ComposeDefaults(...)]</c>
            /// attribute to learn the Kotlin parameter names + bit
            /// positions. Required when the JNI signature has a
            /// <c>$default</c> slot; must be omitted otherwise. The
            /// generator cross-checks this against the signature and
            /// reports CN2005 on a mismatch.</para>
            /// <para><b>InstanceField</b>: when set, the bridge calls an
            /// instance method on a Kotlin <c>object</c> singleton — name
            /// the <c>$$INSTANCE</c>-style static field
            /// (e.g. <c>INSTANCE</c>) and the generator emits
            /// <c>GetMethodID</c> + <c>CallObjectMethod</c> instead.</para>
            /// </remarks>
            [global::System.AttributeUsage(global::System.AttributeTargets.Method,
                                           AllowMultiple = false)]
            internal sealed class ComposeBridgeAttribute : global::System.Attribute
            {
                public ComposeBridgeAttribute() { }
                public string Class { get; set; } = "";
                public string JvmName { get; set; } = "";
                public string Signature { get; set; } = "";
                public global::System.Type? Defaults { get; set; }
                public string? InstanceField { get; set; }
            }

            /// <summary>
            /// Apply alongside <see cref="ComposeBridgeAttribute"/> on a
            /// <c>partial</c> method in <c>ComposeBridges</c> to have
            /// <c>ComposeFacadeGenerator</c> emit the corresponding
            /// user-facing facade class (a <c>public sealed partial</c>
            /// <see cref="ComposableNode"/> / <see cref="ComposableContainer"/>
            /// in <c>namespace ComposeNet</c>).
            /// </summary>
            /// <remarks>
            /// The facade's constructor, base class, and <c>Render</c> body
            /// are inferred from the bridge's C# parameter shape:
            /// <list type="bullet">
            /// <item><description><c>IModifier? modifier</c> → render uses
            /// <c>BuildModifier()</c>; no ctor param.</description></item>
            /// <item><description><c>IFunction0 &lt;name&gt;</c> → ctor takes
            /// <c>System.Action &lt;name&gt;</c>; render wraps in
            /// <c>ComposableLambda0</c>.</description></item>
            /// <item><description><c>IFunction2 content</c> /
            /// <c>IFunction3 content</c> → container shape, base
            /// <c>ComposableContainer</c>; render uses
            /// <c>ComposableLambdas.Wrap2</c> / <c>Wrap3</c>.</description></item>
            /// <item><description>Primitive (<c>string</c>, <c>int</c>,
            /// <c>long</c>, <c>bool</c>, <c>float</c>, <c>double</c>) →
            /// positional ctor parameter.</description></item>
            /// </list>
            /// Anything else (e.g. <c>IFunction1</c> callbacks, value-class
            /// handles, the caller-controlled <c>int defaults</c> hatch) is
            /// rejected via diagnostic CN3002 — leave that bridge hand-written.
            /// <para><b>Docs &amp; overrides:</b> the generated class is
            /// <c>sealed partial</c>. Add a sibling stub
            /// <c>src/ComposeNet.Compose/&lt;Name&gt;.cs</c> with the
            /// <c>///&lt;summary&gt;</c> comment (and any extra members
            /// the facade needs) — the generator deliberately does not
            /// emit a summary so the stub owns it.</para>
            /// </remarks>
            [global::System.AttributeUsage(global::System.AttributeTargets.Method,
                                           AllowMultiple = false)]
            internal sealed class ComposeFacadeAttribute : global::System.Attribute
            {
                public ComposeFacadeAttribute() { }

                /// <summary>Optional override for the generated class name. Defaults to the bridge method name.</summary>
                public string? ClassName { get; set; }

                /// <summary>
                /// Optional scope to publish from an <c>IFunction3</c> content
                /// lambda. <c>"Row"</c> (e.g. <see cref="NavigationBar"/>,
                /// <see cref="Badge"/>) or <c>"Column"</c>. The lambda
                /// receives the scope handle and pushes it via
                /// <c>RenderContext.PushScope(scope, ScopeKind.X)</c> so
                /// child composables can read it. Requires a bridge with
                /// an <c>IFunction3 content</c> parameter.
                /// </summary>
                public string? Scope { get; set; }
            }
        }
        """;
}
